code = """import json
import re

# Get all Literature & Fiction books
books_key = 'var_functions.query_db:26'
books_result = locals().get(books_key)
if isinstance(books_result, str):
    with open(books_result, 'r') as f:
        all_books = json.load(f)
else:
    all_books = books_result

# Get perfect books from previous analysis
perfect_books_key = 'var_functions.execute_python:36'
perfect_result = locals().get(perfect_books_key)
if isinstance(perfect_result, str):
    perfect_books = json.loads(perfect_result)
else:
    perfect_books = perfect_result

# Create a dict for easy lookup
all_books_dict = {book['book_id']: book for book in all_books}

# Verify each perfect rating book details
verified_books = []
for perfect_book in perfect_books:
    book_id = perfect_book['book_id']
    if book_id in all_books_dict:
        book = all_books_dict[book_id]
        # Verify it's English language
        details = book.get('details', '').lower()
        categories = book.get('categories', '').lower()
        
        is_english = 'english' in details
        is_literature_fiction = 'literature & fiction' in categories or 'literature"' in categories
        
        verified_books.append({
            'title': perfect_book['title'],
            'book_id': book_id,
            'avg_rating': perfect_book['avg_rating'],
            'rating_count': perfect_book['rating_count'],
            'categories': book.get('categories'),
            'language': 'English' if is_english else 'Unknown'
        })

print('__RESULT__:')
print(json.dumps(verified_books, indent=2))"""

